@js:
var doc = org.jsoup.Jsoup.parse(result);
var baseUrl = "https://dmbus.cc";

// 1. 获取动漫巴士的线路和剧集列表
var lines = doc.select(".play_from li");
var lists = doc.select(".tab_content .play_list");

// 2. 获取当前动漫的名称（用于作为历史记录的唯一标识 Key）
var animeTitle = doc.select(".v_title a").text();
if (!animeTitle || animeTitle.trim() === "") animeTitle = "default_anime";

if (lines.size() == 0 || lists.size() == 0) {
    "未获取到播放列表";
} else {
    function cleanText(str) { return String(str || "").replace(/\s+/g, "").trim(); }
    function fullUrl(href) {
        href = String(href || "").trim();
        return href.indexOf("http") == 0 ? href : baseUrl + href;
    }
    function esc(str) {
        return String(str || "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#39;");
    }
    function jsEsc(str) {
        return String(str || "").replace(/\\/g, "\\\\").replace(/'/g, "\\'").replace(/"/g, "\\\"").replace(/\n/g, "").replace(/\r/g, "");
    }

    var firstUrl = "";
    var firstEp = lists.first().select("li a").last(); 
    if (firstEp != null) {
        firstUrl = fullUrl(firstEp.attr("href"));
    }

    var html = "";

    // CSS 样式 (新增历史记录按钮的样式)
    html += "<style>";
    html += "*{box-sizing:border-box;} .play-wrap{padding:10px;background:#f5f6fa;border-radius:16px;font-family:-apple-system,sans-serif;}";
    html += ".player-box{position:relative;width:100%;aspect-ratio:16/9;background:#000;border-radius:16px;overflow:hidden;margin-bottom:12px;box-shadow:0 8px 22px rgba(0,0,0,.25);}";
    html += ".player-box iframe, .player-box video{width:100%;height:100%;background:#000;display:block;border:none;}";
    html += ".player-loading{position:absolute;left:0;top:0;width:100%;height:100%;display:flex;align-items:center;justify-content:center;color:#ddd;background:#000;font-size:14px;z-index:2;}";
    html += ".line-tabs{display:flex;gap:8px;overflow-x:auto;padding:2px 0 10px;margin:0 0 8px;}";
    html += ".line-tabs button{flex:0 0 auto;border:none;padding:8px 14px;border-radius:999px;background:#eef2ff;color:#374151;font-size:14px;font-weight:700;}";
    html += ".line-tabs button.active{background:#4f8cff;color:#fff;box-shadow:0 5px 14px rgba(79,140,255,.32);}";
    html += ".line-panel{display:none;} .line-panel.active{display:block;}";
    html += ".episode-box{display:grid;grid-template-columns:repeat(4,1fr);gap:9px;}";
    html += ".episode-box button{width:100%;padding:10px 6px;text-align:center;background:#fff;color:#222;border-radius:12px;border:1px solid #e5e7eb;font-size:14px;font-weight:650;}";
    html += ".episode-box button.active{background:#4f8cff;color:#fff;border-color:#4f8cff;}";
    html += ".episode-box button.watched{background:#dbeafe;border-color:#93c5fd;}";
    html += "@media(max-width:360px){.episode-box{grid-template-columns:repeat(3,1fr);}}";

    // 历史记录栏样式
    html += ".history-bar{display:flex;justify-content:space-between;align-items:center;padding:10px 4px 4px;margin-top:8px;}";
    html += ".history-tips{font-size:12px;color:#9ca3af;}";
    html += ".history-bar button{background:transparent;border:1px solid #d1d5db;padding:4px 10px;border-radius:6px;font-size:12px;color:#6b7280;}";
    html += "</style>";

    html += "<div class='play-wrap'>";

    // 播放器容器
    html += "<div id='playerBox' class='player-box'>";
    html += "<div id='playerLoading' class='player-loading'>加载中...</div>";
    html += "<iframe id='videoPlayer' allowfullscreen='true'></iframe>";
    html += "</div>";

    html += "<div class='line-tabs'>";
    for (var t = 0; t < lines.size(); t++) {
        var tabName = cleanText(lines.get(t).text());
        html += "<button type='button' id='tab_" + t + "' class='" + (t == 0 ? "active" : "") + "' onclick='showLine(" + t + ")'>" + esc(tabName) + "</button>";
    }
    html += "</div>";

    for (var x = 0; x < lists.size(); x++) {
        html += "<div id='panel_" + x + "' class='line-panel " + (x == 0 ? "active" : "") + "'>";
        html += "<div class='episode-box'>";

        var episodes = lists.get(x).select("li a");
        for (var j = episodes.size() - 1; j >= 0; j--) {
            var ep = episodes.get(j);
            var title = "第" + cleanText(ep.text()) + "集";
            var url = fullUrl(ep.attr("href"));
            var realIdx = episodes.size() - 1 - j; 
            html += "<button type='button' id='ep_" + x + "_" + realIdx + "' data-url='" + jsEsc(url) + "' onclick=\"changePlay('" + jsEsc(url) + "','ep_" + x + "_" + realIdx + "')\">" + esc(title) + "</button>";
        }
        html += "</div></div>";
    }

    // 底部添加历史记录控制条
    html += "<div class='history-bar'>";
    html += "<span class='history-tips' id='historyTips'>已自动记录观看集数</span>";
    html += "<button onclick='clearHistory()'>🗑 清除历史</button>";
    html += "</div>";

    html += "</div>";

    // 注入前端交互 JS
    html += "<script>";
    html += "var firstPlayUrl='" + jsEsc(firstUrl) + "';";

    // 历史记录核心逻辑
    html += "var storageKey = 'dmbus_history_" + jsEsc(cleanText(animeTitle)) + "';"; // 动态使用动漫名作为Key

    html += "function saveHistory(id, url) {";
    html += "  try { localStorage.setItem(storageKey, JSON.stringify({id: id, url: url})); } catch(e) {}";
    html += "}";

    html += "function getHistory() {";
    html += "  try { var data = localStorage.getItem(storageKey); return data ? JSON.parse(data) : null; } catch(e) { return null; }";
    html += "}";

    html += "function clearHistory() {";
    html += "  localStorage.removeItem(storageKey);";
    html += "  var eps = document.querySelectorAll('.episode-box button');";
    html += "  for(var i=0; i<eps.length; i++) eps[i].classList.remove('watched');";
    html += "  document.getElementById('historyTips').innerText = '历史记录已清空';";
    html += "}";

    html += "function restoreHistory() {";
    html += "  var h = getHistory();";
    html += "  if (h && h.id && h.url && document.getElementById(h.id)) {";
    html += "    var parts = h.id.split('_');"; // e.g. ep_0_5
    html += "    if (parts.length === 3) showLine(parts[1]);"; // 自动切换到对应线路Tab
    html += "    changePlay(h.url, h.id, true);"; // 恢复播放
    html += "    return true;";
    html += "  }";
    html += "  return false;";
    html += "}";

    html += "function showLine(index){";
    html += "  var tabs=document.querySelectorAll('.line-tabs button');";
    html += "  var panels=document.querySelectorAll('.line-panel');";
    html += "  for(var i=0;i<tabs.length;i++){tabs[i].classList.remove('active');panels[i].classList.remove('active');}";
    html += "  document.getElementById('tab_'+index).classList.add('active');";
    html += "  document.getElementById('panel_'+index).classList.add('active');";
    html += "}";

    html += "function setActive(id){";
    html += "  var eps=document.querySelectorAll('.episode-box button');";
    html += "  for(var i=0;i<eps.length;i++) eps[i].classList.remove('active');";
    html += "  var now=document.getElementById(id);";
    html += "  if(now){ now.classList.add('active'); now.classList.add('watched'); }";
    html += "}";

    html += "function changePlay(playUrl, id, isHistory){";
    html += "  setActive(id);";
    html += "  saveHistory(id, playUrl);"; // 触发播放时自动存入 localStorage

    html += "  var btn = document.getElementById(id);";
    html += "  if(btn && document.getElementById('historyTips')) {";
    html += "    document.getElementById('historyTips').innerText = isHistory ? '已为您恢复播放: ' + btn.innerText : '当前播放: ' + btn.innerText;";
    html += "  }";

    html += "  var loading=document.getElementById('playerLoading');";
    html += "  var video=document.getElementById('videoPlayer');";
    html += "  loading.style.display='flex'; video.style.display='none';";
    html += "  loading.innerHTML='正在获取播放源...';";

    html += "  fetch(playUrl).then(res => res.text()).then(txt => {";
    html += "    var match = txt.match(/<iframe[^>]+src=\"([^\"]+)\"/i);";
    html += "    if(match && match[1]){";
    html += "       loading.style.display='none';";
    html += "       video.style.display='block';";
    html += "       video.src=match[1];";
    html += "    } else { loading.innerHTML='提取播放器失败'; }";
    html += "  }).catch(err => { loading.innerHTML='网络请求失败'; });";
    html += "}";

    // 启动逻辑：优先尝试恢复历史记录，如果没有则默认播放第一集
    html += "setTimeout(function(){";
    html += "  if(!restoreHistory()) { changePlay(firstPlayUrl, 'ep_0_0', false); }";
    html += "}, 100);";
    html += "</script>";

    html;
}
